#[tokio::test]
async fn test_migration_from_legacy_schema() {
    // Create database with old schema (no sources table, no source_id column)
    let temp_dir = tempdir().unwrap();
    let db_path = temp_dir.path().join("legacy.db");

    // Manually create old schema
    let conn = rusqlite::Connection::open(&db_path).unwrap();
    conn.execute_batch(r#"
        CREATE TABLE conversations (
            id TEXT PRIMARY KEY,
            agent_id INTEGER,
            title TEXT,
            started_at INTEGER,
            ended_at INTEGER,
            source_path TEXT
        );
        CREATE TABLE agents (id INTEGER PRIMARY KEY, slug TEXT);
        INSERT INTO agents VALUES (1, 'claude-code');
        INSERT INTO conversations VALUES ('conv1', 1, 'Test', 1700000000, NULL, '/path');
    "#).unwrap();
    drop(conn);

    // Open with new schema (should migrate)
    let db = Database::open(&db_path).await.unwrap();

    // Verify migration worked
    assert!(db.has_table("sources").await.unwrap());
    assert!(db.has_column("conversations", "source_id").await.unwrap());

    // Existing data should have source_id = NULL (will be treated as local)
    let conv = db.get_conversation("conv1").await.unwrap().unwrap();
    assert!(conv.source_id.is_none());  // Legacy data
    assert_eq!(conv.effective_source_type(), SourceType::Local);
}

