 {"id":"coding_agent_session_search-fxaw","title":"P3.3: sqlite-wasm Integration","description":"# sqlite-wasm Integration

**Parent Phase:** coding_agent_session_search-uok7 (Phase 3: Web Viewer)
**Depends On:** P3.2 (Decryption Worker)
**Estimated Duration:** 2-3 days

## Goal

Initialize sqlite-wasm with the decrypted database and provide a query API for the viewer components.

## Technical Approach

### Database Module

```javascript
// database.js
let db = null;

/**
 * Initialize sqlite-wasm with decrypted database bytes.
 * Uses OPFS if available, falls back to in-memory.
 */
export async function initDatabase(dbBytes) {
    const sqlite3 = await loadSqliteWasm();

    // Try OPFS first (faster subsequent loads)
    if (navigator.storage?.getDirectory) {
        try {
            await writeBytesToOPFS(dbBytes);
            db = await sqlite3.oo1.OpfsDb('cass-archive.sqlite3');
            console.log('Loaded from OPFS');
            return;
        } catch (e) {
            console.warn('OPFS unavailable, using in-memory:', e);
        }
    }

    // Fallback: in-memory
    db = new sqlite3.oo1.DB();
    const ptr = sqlite3.wasm.allocFromTypedArray(dbBytes);
    db.deserialize(ptr, dbBytes.length);
    sqlite3.wasm.dealloc(ptr);
    console.log('Loaded into memory');
}

/**
 * Load sqlite-wasm module.
 */
async function loadSqliteWasm() {
    const { default: sqlite3InitModule } = await import('./vendor/sqlite3.js');
    return await sqlite3InitModule();
}

/**
 * Write database bytes to OPFS.
 */
async function writeBytesToOPFS(bytes) {
    const root = await navigator.storage.getDirectory();
    const dir = await root.getDirectoryHandle('cass-cache', { create: true });
    const handle = await dir.getFileHandle('cass-archive.sqlite3', { create: true });
    const writable = await handle.createWritable();
    await writable.write(bytes);
    await writable.close();
}
```

### Scoped Query Pattern (Prevents Memory Leaks)

```javascript
/**
 * Execute query with automatic resource cleanup.
 * Inspired by bv's withDatabaseScope() pattern.
 */
export function withQuery(sql, params = [], callback) {
    const stmt = db.prepare(sql);
    try {
        if (params.length > 0) {
            stmt.bind(params);
        }
        return callback(stmt);
    } finally {
        stmt.free();  // Critical: free WASM memory
    }
}

/**
 * Execute query and return all results.
 */
export function queryAll(sql, params = []) {
    return withQuery(sql, params, (stmt) => {
        const results = [];
        while (stmt.step()) {
            results.push(stmt.getAsObject());
        }
        return results;
    });
}

/**
 * Execute query and return first row.
 */
export function queryOne(sql, params = []) {
    return withQuery(sql, params, (stmt) => {
        return stmt.step() ? stmt.getAsObject() : null;
    });
}

/**
 * Execute query and return single value.
 */
export function queryValue(sql, params = []) {
